package com.example.myapp.deeplink

import android.app.Activity
import android.content.Context
import android.content.Intent
import android.net.Uri

object DeepLinkHandler {
    fun handle(context: Context, uri: Uri?): Boolean {
        if (uri == null) return false
        if (!uri.scheme.equals("myapp", ignoreCase = true)) return false

        val segments = uri.pathSegments
        val host = uri.host.orEmpty().lowercase()

        return when {
            host == "profile" -> {
                val userId = segments.firstOrNull()
                if (userId.isNullOrBlank()) {
                    false
                } else {
                    val intent = Intent(context, ProfileActivity::class.java).apply {
                        putExtra(ProfileActivity.EXTRA_USER_ID, userId)
                        addFlagsIfNeeded(context)
                    }
                    context.startActivity(intent)
                    true
                }
            }

            host == "payment" && segments.firstOrNull().equals("confirm", ignoreCase = true) -> {
                val intent = Intent(context, PaymentConfirmActivity::class.java).apply {
                    addFlagsIfNeeded(context)
                }
                context.startActivity(intent)
                true
            }

            else -> false
        }
    }

    fun handle(context: Context, deepLink: String?): Boolean {
        if (deepLink.isNullOrBlank()) return false
        return runCatching { Uri.parse(deepLink) }
            .getOrNull()
            ?.let { handle(context, it) }
            ?: false
    }

    private fun Intent.addFlagsIfNeeded(context: Context) {
        if (context !is Activity) {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        }
    }
}

class ProfileActivity : Activity() {
    companion object {
        const val EXTRA_USER_ID = "extra_user_id"
    }
}

class PaymentConfirmActivity : Activity()

class DeepLinkEntryActivity : Activity() {
    override fun onStart() {
        super.onStart()
        DeepLinkHandler.handle(this, intent?.data)
        finish()
    }
